#!/usr/bin/env bash
# ============================================================
#  DEVSTUDIO — Script de instalación completa
#  Uso: bash setup.sh [nombre-del-proyecto]
# ============================================================
set -e

PROJECT="${1:-devstudio-web}"
echo ""
echo ">_ DEVSTUDIO — Creando proyecto: $PROJECT"
echo ""

# 1. Crear proyecto con Vite + React + SWC
npm create vite@latest "$PROJECT" -- --template react-swc
cd "$PROJECT"

# 2. Instalar dependencias
npm install

# 3. Crear carpetas
mkdir -p src/components src/hooks

# 4. Eliminar archivos de plantilla que no necesitamos
rm -f src/App.css src/assets/react.svg public/vite.svg

echo "Escribiendo archivos del proyecto..."

